external_knowledge:
- 'hottest wildfires' refers to those with the highest hotspot temperatures; 
- 'area between latitudes 30 and 50, and longitudes -120 and -60' refers to the geographical area bounded by these coordinates; 
- 'occurred in the year 2022' refers to the start date of the wildfires being between January 1, 2022, and December 31, 2022.

sql:
SELECT ti.image_id, ti.frp
FROM thermal_imagery ti
WHERE ti.confidence = (
    SELECT MAX(confidence) FROM thermal_imagery
);

SELECT COUNT(image_id) AS number_of_images
FROM thermal_imagery
WHERE satellite = 'SatelliteX' AND acq_date = '2023-10-01';

SELECT COUNT(*) AS image_count
FROM thermal_imagery
WHERE satellite = 'Specific_Satellite_Name';

SELECT image_id, acq_date
FROM thermal_imagery
ORDER BY acq_date DESC;

SELECT image_id, acq_date, acq_time
FROM thermal_imagery
ORDER BY acq_date ASC, acq_time ASC;
